+vi.mock('../utils/config.js', () => ({
+  getConfig: vi.fn(() => ({ signingKey: 'test-key' })),
+  validateRunId: vi.fn((id: string) => id.length === 26 && /^[0-9A-HJKMNP-TV-Z]{26}$/.test(id)),
